const GLOSSARY_CCSP = [
  { term:"Acceptable Use Policy (AUP)", def:"A documented set of rules governing how an organization's IT resources, networks, and internet access may be used by employees, contractors, and other authorized users. Violations may result in disciplinary action or termination." },
  { term:"Access Control", def:"Policies, procedures, and mechanisms that restrict access to systems, data, and resources based on identity, role, or attributes. Encompasses both physical and logical controls." },
  { term:"Advanced Encryption Standard (AES)", def:"A symmetric block cipher adopted by NIST in 2001 as the U.S. federal encryption standard. Supports key sizes of 128, 192, and 256 bits and is the most widely deployed encryption algorithm in the world." },
  { term:"Amazon EC2", def:"Amazon Elastic Compute Cloud — a web service that provides resizable virtual compute capacity in the cloud. Users can launch virtual server instances of various sizes on demand, paying only for what they use." },
  { term:"Annual Loss Expectancy (ALE)", def:"A risk metric calculated as ALE = SLE × ARO (Single Loss Expectancy × Annualized Rate of Occurrence). Represents the expected financial loss from a specific threat over a one-year period." },
  { term:"Annual Rate of Occurrence (ARO)", def:"An estimate of how frequently a specific threat event is expected to occur within a one-year period. Used in quantitative risk analysis to calculate Annual Loss Expectancy (ALE)." },
  { term:"Anonymization", def:"The irreversible process of altering data so that individuals cannot be identified, directly or indirectly. Unlike pseudonymization, true anonymization cannot be reversed. Properly anonymized data falls outside the scope of GDPR and similar privacy regulations." },
  { term:"Anything-as-a-Service (XaaS)", def:"A collective term for all services delivered over the internet through a subscription model, encompassing IaaS, PaaS, SaaS, and other specialized cloud delivery models. Reflects the broad expansion of on-demand cloud services." },
  { term:"Apache CloudStack", def:"An open-source cloud computing software platform used to deploy and manage large networks of virtual machines. Provides a full stack of cloud infrastructure features and competes with OpenStack as a private/hybrid cloud solution." },
  { term:"API Gateway", def:"A server that acts as an entry point for clients accessing backend services via APIs. Handles authentication, rate limiting, request routing, protocol translation, and monitoring, centralizing cross-cutting concerns across multiple microservices." },
  { term:"Application Normative Framework (ANF)", def:"A framework that defines the security, governance, and operational standards that applications deployed within a cloud environment must comply with. Establishes baseline requirements for cloud-hosted applications." },
  { term:"Application Programming Interfaces (APIs)", def:"Sets of protocols, definitions, and tools that allow different software applications to communicate with each other. APIs define the methods and data formats applications use to request and exchange information." },
  { term:"Application Security Management Process (ASMP)", def:"A structured, repeatable process for integrating security activities throughout the software development lifecycle. Includes threat modeling, secure code review, vulnerability testing, and security requirements management." },
  { term:"Application Virtualization", def:"A technology that encapsulates an application from the underlying operating system, allowing it to run in an isolated environment without being traditionally installed. Enables centralized management and eliminates dependency conflicts." },
  { term:"Asymmetric Encryption", def:"Encryption using a mathematically linked key pair — a public key (shareable) for encryption and a private key (secret) for decryption. Underpins PKI, TLS, and digital signatures. Also called public-key cryptography." },
  { term:"Auditability", def:"The ability of a system to provide a complete, tamper-evident, chronological record of all actions and events. Enables compliance verification, forensic investigation, and accountability by ensuring activities can be traced to responsible parties." },
  { term:"Australian Privacy Act of 1988", def:"Australian federal legislation that regulates the handling of personal information by government agencies and private sector organizations. Sets out 13 Australian Privacy Principles (APPs) governing collection, use, disclosure, and security of personal data." },
  { term:"Authentication", def:"The process of verifying the identity of a user, device, or system before granting access. Common factors include something you know (password), something you have (token), and something you are (biometric)." },
  { term:"Authorization", def:"The process of determining what resources, operations, or data an authenticated entity is permitted to access or perform. Follows authentication and is governed by access control policies such as RBAC or ABAC." },
  { term:"Availability", def:"One of the three pillars of the CIA triad. Ensures that authorized users can access systems, services, and data when needed. Threats to availability include DDoS attacks, hardware failures, ransomware, and natural disasters." },
  { term:"Big Data", def:"Extremely large and complex data sets that cannot be processed by traditional database tools. Characterized by the three V's: Volume (massive scale), Velocity (high-speed generation), and Variety (structured and unstructured formats). Requires distributed processing frameworks like Hadoop or Spark." },
  { term:"Bit Splitting", def:"A data security technique that divides encrypted data into multiple fragments and stores them in separate locations. Ensures no single location holds a usable portion of the data, reducing the risk of unauthorized disclosure even if one location is compromised." },
  { term:"Business Continuity and Disaster Recovery (BC/DR)", def:"A combined practice addressing how an organization plans for, responds to, and recovers from disruptive events. Business Continuity focuses on maintaining operations during a disruption; Disaster Recovery focuses on restoring IT systems and data afterward." },
  { term:"Business Impact Analysis (BIA)", def:"A systematic process that identifies critical business functions and quantifies the impact of their disruption over time. Establishes Recovery Time Objectives (RTO) and Recovery Point Objectives (RPO) to prioritize recovery efforts." },
  { term:"Business Rules", def:"Explicit statements that define or constrain some aspect of business processes, policies, or operations. In cloud and application contexts, business rules govern data validation, workflow logic, access conditions, and compliance requirements encoded into systems." },
  { term:"Central Processing Unit (CPU)", def:"The primary component of a computer that executes instructions from programs. In cloud computing, CPU resources are virtualized and allocated to virtual machines or containers as needed, billed per vCPU core or compute-hour." },
  { term:"Chain of Custody", def:"A documented, unbroken chronological record showing who collected, handled, transferred, or analyzed evidence. Critical in digital forensics and legal proceedings to demonstrate that evidence has not been tampered with or contaminated." },
  { term:"Cloud Access Security Broker (CASB)", def:"A security policy enforcement point positioned between cloud service consumers and providers. CASBs provide visibility into cloud usage, enforce security policies (DLP, encryption, access control), and protect against threats across sanctioned and unsanctioned cloud services." },
  { term:"Cloud Administrator", def:"An IT professional responsible for managing and maintaining a cloud computing environment. Duties include provisioning resources, monitoring performance, managing access controls, enforcing security policies, and ensuring uptime and compliance." },
  { term:"Cloud App (Cloud Application)", def:"Software that is deployed on and accessed from cloud infrastructure rather than locally installed on a user's device. Cloud apps leverage scalability, high availability, and multi-tenancy of cloud platforms, typically accessed via a web browser or API." },
  { term:"Cloud Application Architect", def:"A technical specialist who designs the structure and components of applications built for cloud environments. Responsibilities include selecting cloud services, designing for scalability and resilience, defining integration patterns, and ensuring security and compliance." },
  { term:"Cloud Application Management Platform (CAMP)", def:"A specification and platform that provides a standard way to manage cloud-hosted applications across multiple cloud providers. CAMP aims to simplify deployment, lifecycle management, and portability of applications between different cloud environments." },
  { term:"Cloud Architect", def:"A professional who designs an organization's cloud computing strategy and infrastructure. Responsible for selecting cloud services, designing network topology, defining security controls, optimizing costs, and ensuring the overall cloud environment meets business requirements." },
  { term:"Cloud Backup", def:"The process of copying and storing data to a remote cloud-based server or service for protection against data loss. Provides off-site redundancy, version control, and scalable storage without requiring the organization to manage physical backup infrastructure." },
  { term:"Cloud Backup Service Provider", def:"A company that offers managed cloud backup services, storing customer data in remote data centers. Provides data protection, retention management, encryption, and recovery capabilities as a subscription service, relieving customers of backup infrastructure management." },
  { term:"Cloud Backup Solutions", def:"Technologies, services, and platforms that enable organizations to back up data to cloud storage. May include agent-based backup software, cloud-native backup services, or hybrid solutions combining on-premises and cloud backup targets." },
  { term:"Cloud Computing", def:"A model for enabling ubiquitous, convenient, on-demand network access to a shared pool of configurable computing resources (networks, servers, storage, applications, services) that can be rapidly provisioned and released with minimal management effort. Defined by NIST SP 800-145." },
  { term:"Cloud Computing Accounting Software", def:"Financial management and accounting applications delivered via the cloud as SaaS solutions. Examples include QuickBooks Online, Xero, and NetSuite. These eliminate local installation requirements and provide real-time financial data access from any device." },
  { term:"Cloud Computing Reseller", def:"A company or individual that purchases cloud services from a primary provider and resells them to end customers, often adding value through bundled services, support, customization, or management. Acts as an intermediary in the cloud services supply chain." },
  { term:"Cloud Data Architect", def:"A specialist who designs and manages data storage, processing, and management strategies within cloud environments. Responsible for data modeling, selecting cloud data services (databases, data lakes, warehouses), ensuring data quality, and designing data governance frameworks." },
  { term:"Cloud Database", def:"A database service hosted and managed in a cloud environment, accessible over the internet. May be offered as DBaaS (Database as a Service), providing automated provisioning, scaling, backup, patching, and high availability without infrastructure management." },
  { term:"Cloud Developer", def:"A software developer who specializes in building applications designed to run in cloud environments. Proficient in cloud-native architectures, serverless computing, containerization, cloud APIs, and DevOps practices for deploying and scaling applications in the cloud." },
  { term:"Cloud Enablement", def:"The process of transforming an organization's infrastructure, applications, and processes to effectively utilize cloud computing. Includes migrating workloads, integrating cloud services, training staff, updating security policies, and establishing cloud governance frameworks." },
  { term:"Cloud Management", def:"The administration, monitoring, and optimization of cloud computing resources and services. Encompasses cost management, performance monitoring, security enforcement, compliance reporting, and lifecycle management of cloud workloads across single or multi-cloud environments." },
  { term:"Cloud Migration", def:"The process of moving data, applications, workloads, or services from on-premises infrastructure to cloud environments, or between cloud providers. Migration strategies include Rehost (lift-and-shift), Replatform, Refactor, Repurchase, Retain, and Retire (the 6 R's)." },
  { term:"Cloud OS", def:"A cloud operating system — software that manages cloud resources and infrastructure, providing services analogous to a traditional OS but for distributed cloud environments. Examples include OpenStack and VMware vSphere. Orchestrates compute, storage, and networking." },
  { term:"Cloud Portability", def:"The ability to move workloads, data, and applications between different cloud providers or between cloud and on-premises environments with minimal friction. Reduces vendor lock-in risk and enables organizations to adopt best-of-breed services." },
  { term:"Cloud Provider", def:"An organization that offers cloud computing services — including infrastructure, platforms, or software — over the internet on a pay-as-you-go basis. Major providers include AWS, Microsoft Azure, and Google Cloud Platform." },
  { term:"Cloud Provisioning", def:"The process of allocating and configuring cloud resources (compute, storage, networking) to meet user or application needs. Can be self-service through a portal, automated via APIs, or managed by a cloud administrator." },
  { term:"Cloud Security Alliance (CSA)", def:"A non-profit organization that promotes the use of best practices for providing security assurance within cloud computing. Publishes the Cloud Controls Matrix, Security Guidance, and operates the STAR certification program." },
  { term:"Cloud Security Alliance (CSA) Cloud Controls Matrix (CCM)", def:"A cybersecurity control framework specifically designed for cloud computing. Provides 197 control objectives across 17 domains, mapping to major standards including ISO 27001, PCI DSS, HIPAA, and COBIT. Used for cloud vendor assessment and compliance." },
  { term:"Cloud Server Hosting", def:"A hosting model where websites, applications, or services run on virtual servers provisioned from a pool of physical cloud infrastructure. Offers greater scalability and reliability compared to traditional dedicated server hosting, as resources can be adjusted dynamically." },
  { term:"Cloud Services Broker", def:"An intermediary entity that manages the use, performance, and delivery of cloud services, negotiating relationships between cloud providers and cloud consumers. May aggregate, integrate, or customize cloud services to meet specific business needs." },
  { term:"Cloud Storage", def:"A model of data storage where digital data is stored in logical pools hosted on remote servers managed by a cloud provider. Accessible over the internet, cloud storage offers scalability, durability, and geographic redundancy (e.g., Amazon S3, Azure Blob Storage)." },
  { term:"Cloud Testing", def:"The process of using cloud infrastructure and services to perform software testing activities. Includes load testing, performance testing, and security testing of both cloud-hosted applications and the cloud environment itself." },
  { term:"Cloud Washing", def:"A marketing practice where vendors falsely or misleadingly label existing non-cloud products or services as 'cloud' to capitalize on the cloud computing trend. True cloud services should exhibit the NIST-defined characteristics: on-demand self-service, broad network access, resource pooling, rapid elasticity, and measured service." },
  { term:"Common Criteria", def:"An international standard (ISO/IEC 15408) for computer security certification. Provides a framework for defining security requirements (Protection Profiles) and evaluating products against those requirements at defined Evaluation Assurance Levels (EAL 1–7)." },
  { term:"Community Cloud", def:"A cloud deployment model where infrastructure is shared by several organizations with common concerns (e.g., mission, security requirements, compliance). May be managed by the organizations themselves or a third party, and may be on or off premises." },
  { term:"Compute", def:"The processing power used to run applications and workloads. In cloud computing, compute resources (CPUs, memory) are provided as virtual machines, containers, or serverless functions, scaled on demand and billed based on usage." },
  { term:"Confidentiality", def:"One of the three pillars of the CIA triad. Ensures that information is accessible only to those authorized to access it. Achieved through encryption, access controls, data classification, and need-to-know policies." },
  { term:"Containers / Containerization", def:"A lightweight OS-level virtualization method that packages an application and its dependencies into a self-contained unit (container). Containers share the host OS kernel, making them more efficient than VMs. Docker and Kubernetes are the dominant container technologies." },
  { term:"Content Delivery Network (CDN)", def:"A geographically distributed network of proxy servers and data centers that cache and deliver web content to users from locations closest to them. Reduces latency, improves load times, and provides resilience against traffic spikes and DDoS attacks." },
  { term:"Control", def:"A safeguard or countermeasure designed to prevent, detect, or correct security incidents and reduce risk. Controls may be technical (firewalls, encryption), administrative (policies, training), or physical (locks, cameras). Categorized as preventive, detective, corrective, or compensating." },
  { term:"Converged Networking Model", def:"A network architecture that combines multiple types of network traffic — data, voice, video, and storage — over a single unified network infrastructure. Reduces complexity, cost, and the need for separate networks for each traffic type." },
  { term:"Corporate Governance", def:"The system of rules, practices, and processes by which a company is directed and controlled. In IT and cloud security, corporate governance establishes accountability, defines roles and responsibilities, and ensures IT strategy aligns with business objectives and legal obligations." },
  { term:"Criminal Law", def:"The body of law that relates to crimes and their prosecution by the government. In cybersecurity contexts, criminal law covers unauthorized access (hacking), data theft, cyberstalking, ransomware attacks, and other computer crimes enforced by statutes such as the CFAA." },
  { term:"Cross-Site Scripting (XSS)", def:"A web application vulnerability where attackers inject malicious client-side scripts into web pages viewed by other users. Can be used to steal session cookies, redirect users, or perform actions on behalf of victims. Prevented by input validation and output encoding." },
  { term:"Crypto-Shredding", def:"A data destruction technique that renders encrypted data permanently unreadable by destroying the encryption keys rather than the data itself. Particularly useful in cloud environments where physical data deletion is impractical, and as a GDPR 'right to erasure' mechanism." },
  { term:"Database Activity Monitoring (DAM)", def:"A security technology that monitors and analyzes database activity in real time, independent of native database audit logs. Detects unauthorized access, SQL injection, privilege abuse, and other anomalous behavior without impacting database performance." },
  { term:"Data Loss Prevention (DLP)", def:"A set of tools and processes that monitor, detect, and prevent the unauthorized transmission, access, or exfiltration of sensitive data. DLP solutions can operate at the network, endpoint, and cloud levels, enforcing policies around data in use, in transit, and at rest." },
  { term:"Data Masking", def:"A data security technique that replaces sensitive data with realistic but fictitious values, preserving the format and usability of the data for development, testing, or analytics while protecting actual sensitive information from exposure." },
  { term:"Degaussing", def:"A data sanitization method that exposes magnetic storage media (hard drives, magnetic tapes) to a powerful alternating magnetic field, destroying the stored data. Effective for magnetic media but does not work on SSDs or flash storage." },
  { term:"Demilitarized Zone (DMZ)", def:"A network segment that sits between a trusted internal network and an untrusted external network (internet), hosting publicly accessible services such as web servers and email gateways. Limits the exposure of internal systems by adding a buffer zone." },
  { term:"Digital Rights Management (DRM)", def:"Technologies and policies used to control access to and usage of copyrighted digital content. DRM enforces licensing restrictions, prevents unauthorized copying, and enables content owners to specify how, when, and where digital assets may be used." },
  { term:"Domain Name System (DNS)", def:"A hierarchical naming system that translates human-readable domain names (e.g., www.example.com) into IP addresses. Operates as the internet's 'phone book.' DNS poisoning and hijacking are significant security threats; DNSSEC was developed to add integrity verification." },
  { term:"Domain Name System Security Extensions (DNSSEC)", def:"A suite of IETF specifications that add cryptographic authentication to DNS responses. DNSSEC uses digital signatures to verify that DNS responses are authentic and have not been tampered with, protecting against DNS cache poisoning attacks." },
  { term:"Dynamic Application Security Testing (DAST)", def:"A black-box security testing approach that analyzes a running application from the outside by simulating external attacks. Does not require access to source code, making it suitable for testing deployed applications. Complements SAST in a comprehensive AppSec program." },
  { term:"EC Directive 95/46", def:"The European Union Data Protection Directive of 1995 — the predecessor to GDPR. Established baseline data protection standards across EU member states, requiring adequate protection for personal data transferred outside the EU. Superseded by GDPR in May 2018." },
  { term:"eDiscovery", def:"The electronic discovery process of identifying, collecting, preserving, reviewing, and producing electronically stored information (ESI) in response to litigation, investigation, or regulatory requests. Governed by rules such as the U.S. Federal Rules of Civil Procedure (FRCP)." },
  { term:"Elliptic Curve Cryptography (ECC)", def:"A public-key cryptography approach based on the algebraic structure of elliptic curves over finite fields. Provides equivalent security to RSA with much smaller key sizes, making it more efficient for mobile devices and constrained environments." },
  { term:"Encryption", def:"The process of converting plaintext data into ciphertext using a cryptographic algorithm and key, making it unreadable without the corresponding decryption key. Fundamental to protecting data confidentiality in storage and transit." },
  { term:"Encryption Key", def:"A piece of information (typically a string of bits) used by a cryptographic algorithm to transform plaintext into ciphertext and vice versa. Key length, management, and rotation practices critically affect the security of an encryption system." },
  { term:"Enterprise Application", def:"Large-scale software systems designed to support complex business processes across an entire organization. Examples include ERP, CRM, and SCM systems. Cloud-hosted enterprise applications offer scalability and reduced infrastructure overhead." },
  { term:"Enterprise Cloud Backup", def:"A comprehensive backup solution designed for large organizations, providing scalable, policy-driven data protection for cloud and on-premises workloads. Features include centralized management, deduplication, encryption, long-term retention, and compliance reporting." },
  { term:"Enterprise DRM", def:"Digital Rights Management solutions deployed at the enterprise level to protect sensitive internal documents and intellectual property. Controls who can view, edit, copy, print, or forward documents, even after they leave the organization's network perimeter." },
  { term:"Enterprise Risk Management (ERM)", def:"A strategic framework for identifying, assessing, managing, and monitoring risks across an entire organization. ERM integrates risk management into organizational decision-making, balancing risk appetite with business objectives and compliance requirements." },
  { term:"Ephemeral Storage", def:"Temporary storage that exists only for the lifetime of a compute instance (e.g., a virtual machine or container). Data stored ephemerally is lost when the instance terminates or restarts. Suitable for temporary files and caches, not persistent data." },
  { term:"ePHI (Electronic Protected Health Information)", def:"Protected Health Information (PHI) that is created, stored, transmitted, or received in electronic form. Regulated under HIPAA's Security Rule, which requires covered entities and business associates to implement administrative, physical, and technical safeguards for ePHI." },
  { term:"EU General Data Protection Regulation (GDPR)", def:"A comprehensive EU data protection law (Regulation 2016/679) that took effect in May 2018. Governs the collection, processing, storage, and transfer of personal data of EU residents. Establishes rights including erasure, portability, and access, with fines up to €20M or 4% of global turnover." },
  { term:"Federal Information Security Modernization Act (FISMA)", def:"U.S. federal legislation requiring government agencies and their contractors to develop, document, and implement programs to protect information and information systems. Mandates risk management frameworks and reporting to OMB and Congress." },
  { term:"Federated Identity Management (FIM)", def:"A system that enables users to use a single digital identity across multiple organizations or security domains through trust agreements. Users authenticate once with their home organization and are granted access to partner systems without re-authenticating." },
  { term:"Federated Single Sign-On (SSO)", def:"An SSO implementation that extends authentication across organizational boundaries using federation protocols such as SAML, OpenID Connect, or WS-Federation. Allows a user authenticated by one organization's identity provider to access services at partner organizations." },
  { term:"FIPS 140-2", def:"A U.S. government security standard specifying requirements for cryptographic modules. Defines four security levels (1–4) of increasing stringency for hardware and software cryptographic implementations. Required for products used in U.S. government systems handling sensitive data." },
  { term:"Firewall", def:"A network security device (hardware or software) that monitors and controls incoming and outgoing network traffic based on predefined rules. Forms the first line of defense in network security. Types include packet filtering, stateful inspection, application layer (proxy), and next-generation firewalls." },
  { term:"Generally Accepted Accounting Principles (GAAP)", def:"A standardized set of accounting rules, standards, and procedures issued by the Financial Accounting Standards Board (FASB) for financial reporting in the U.S. In cloud computing, GAAP governs how cloud costs, leases, and capitalized development expenses are recorded." },
  { term:"Governance", def:"The framework of policies, processes, roles, and controls through which an organization directs, manages, and monitors its IT and security activities. Ensures alignment with business objectives, legal obligations, and risk tolerance." },
  { term:"Gramm-Leach-Bliley Act (GLBA)", def:"U.S. federal legislation requiring financial institutions to explain their information-sharing practices and protect customers' nonpublic personal information. The Safeguards Rule mandates a written information security program with administrative, technical, and physical safeguards." },
  { term:"Hardware Security Module (HSM)", def:"A dedicated physical computing device that safeguards and manages cryptographic keys and performs cryptographic operations (encryption, decryption, signing) in a tamper-resistant hardware environment. Used to meet high-security key management requirements." },
  { term:"Health Insurance Portability and Accountability Act (HIPAA)", def:"U.S. federal law enacted in 1996 that establishes national standards for protecting sensitive patient health information. The Privacy Rule governs use and disclosure of PHI; the Security Rule requires safeguards for ePHI; the Breach Notification Rule requires reporting of PHI breaches." },
  { term:"Heating, Ventilation, and Air Conditioning (HVAC)", def:"The environmental control systems used in data centers to regulate temperature and humidity. Critical for hardware reliability — data centers typically maintain 64–80°F (18–27°C) and 40–60% relative humidity. HVAC represents a significant portion of data center energy consumption." },
  { term:"Homomorphic Encryption", def:"An advanced form of encryption that allows computations to be performed directly on encrypted data without first decrypting it. The result, when decrypted, matches what would have been obtained by performing the operations on the plaintext. Enables cloud providers to process data they cannot read." },
  { term:"Honeypot", def:"A security decoy system configured to appear as a legitimate target to attract and deceive attackers. Allows security teams to study attacker tactics, techniques, and procedures (TTPs), gather threat intelligence, and divert attackers from real production systems." },
  { term:"Host-Based Intrusion Detection System (HIDS)", def:"A security agent installed on individual hosts (servers, endpoints) that monitors the system for suspicious activity, unauthorized changes, and policy violations. Analyzes system calls, log files, and file integrity. Complements network-based IDS." },
  { term:"Hybrid Cloud", def:"A cloud deployment model that combines private cloud, public cloud, and/or on-premises infrastructure, allowing workloads to move between environments as needs and costs change. Provides greater flexibility and optimization options than single-environment deployments." },
  { term:"Hybrid Cloud Storage", def:"A storage architecture that integrates on-premises storage with cloud storage, enabling data to move seamlessly between local and cloud environments. Organizations keep frequently accessed data on-premises for performance while using cloud storage for archiving, backup, and burst capacity." },
  { term:"Hypervisor", def:"Software (Virtual Machine Monitor) that creates, runs, and manages virtual machines by abstracting underlying physical hardware. Type 1 (bare-metal) hypervisors run directly on hardware (VMware ESXi, Hyper-V); Type 2 hypervisors run on a host OS (VirtualBox, VMware Workstation)." },
  { term:"Identity and Access Management (IAM)", def:"A framework of policies, processes, and technologies for managing digital identities and controlling user access to organizational resources. Encompasses authentication, authorization, user provisioning, single sign-on, and privilege management." },
  { term:"Identity Provider (IdP)", def:"A trusted service that creates, maintains, and manages identity information for users and provides authentication services to relying-party applications. Examples include Active Directory, Okta, and Azure AD. Central to federated identity and SSO architectures." },
  { term:"Information Security Management System (ISMS)", def:"A systematic, risk-based approach to managing sensitive organizational information according to the ISO/IEC 27001 standard. Encompasses people, processes, and technology, addressing risk treatment, policy, asset management, and continual improvement." },
  { term:"Infrastructure as a Service (IaaS)", def:"A cloud service model in which a provider delivers virtualized computing infrastructure — servers, storage, and networking — over the internet on demand. Customers manage the OS, middleware, and applications while the provider manages the underlying hardware." },
  { term:"Integrity", def:"One of the three pillars of the CIA triad. Ensures that data is accurate, complete, and has not been altered in an unauthorized manner. Maintained through hashing, digital signatures, checksums, and access controls." },
  { term:"Internet Engineering Task Force (IETF)", def:"An open standards organization that develops and promotes voluntary internet standards, especially the protocol standards comprising the Internet protocol suite (TCP/IP). Publishes standards as Requests for Comments (RFCs)." },
  { term:"Interoperability", def:"The ability of different systems, organizations, or services to work together and exchange information seamlessly. In cloud computing, interoperability refers to the capability of cloud services to communicate and function together regardless of provider, platform, or technology." },
  { term:"ISO/IEC 27001:2013", def:"The international standard specifying requirements for establishing, implementing, maintaining, and continually improving an Information Security Management System (ISMS). Provides a risk-based approach to information security and is the basis for ISMS certification." },
  { term:"ISO/IEC 27018", def:"An international standard establishing controls for protection of Personally Identifiable Information (PII) in public cloud environments. Extends ISO 27002 with cloud-specific privacy controls and is often used alongside ISO 27001 for cloud provider certification." },
  { term:"ISO/IEC 27034-1", def:"An international standard providing guidance on information security in application development and acquisition. Defines the Application Security Management Process (ASMP) and the concept of Application Normative Frameworks to ensure applications meet defined security requirements." },
  { term:"ITIL (Information Technology Infrastructure Library)", def:"A globally recognized framework of best practices for IT service management (ITSM). Provides a structured approach to aligning IT services with business needs across the service lifecycle: strategy, design, transition, operation, and continual improvement." },
  { term:"Key Management", def:"The comprehensive administration of cryptographic keys throughout their lifecycle: generation, distribution, storage, rotation, revocation, and destruction. Proper key management is essential for maintaining the security of encrypted data; compromised keys render encryption ineffective." },
  { term:"Legacy", def:"Refers to outdated IT systems, applications, or technologies that are still in use despite being superseded by newer solutions. Legacy systems often present security challenges because they may lack modern security features, vendor support, or compatibility with current cloud services." },
  { term:"Local Area Network (LAN)", def:"A computer network that interconnects devices within a limited area — a building, campus, or data center — using wired (Ethernet) or wireless (Wi-Fi) connections. LANs form the foundational network layer within which cloud access and security controls operate." },
  { term:"Logical Design", def:"The abstract representation of a system's architecture, defining components, their relationships, and data flows without specifying physical hardware. In cloud contexts, logical design describes how services, VPCs, security zones, and applications are organized conceptually." },
  { term:"Long-Term Storage", def:"Data storage intended to retain information for extended periods — years or decades — often for compliance, archival, or historical reference purposes. Cloud long-term storage solutions (e.g., AWS Glacier, Azure Archive) offer very low cost but higher retrieval latency." },
  { term:"Managed Service Provider (MSP)", def:"A company that remotely manages a customer's IT infrastructure and end-user systems on a proactive basis and under a subscription model. MSPs offer services such as network monitoring, security management, backup, and cloud infrastructure management." },
  { term:"Management Plane", def:"The interface layer through which cloud resources are provisioned, configured, and monitored — typically via management consoles, CLI tools, or APIs. Securing the management plane is critical; unauthorized access can lead to complete control over cloud resources." },
  { term:"Mean Time Between Failures (MTBF)", def:"The average time elapsed between inherent failures of a system during normal operation. A higher MTBF indicates greater reliability. Used to plan maintenance schedules, predict failures, and calculate availability as MTBF / (MTBF + MTTR)." },
  { term:"Mean Time to Repair (MTTR)", def:"The average time required to repair a failed system and restore it to normal operation. Measures maintainability. Lower MTTR indicates faster recovery, improving overall availability. Calculated as total downtime / number of incidents." },
  { term:"Middleware", def:"Software that acts as an intermediary layer between applications and the underlying infrastructure or other applications. Enables communication, data management, and integration between disparate systems. Examples include message queues, API gateways, and application servers." },
  { term:"Mobile Cloud Storage", def:"Cloud storage accessed and synchronized from mobile devices. Enables users to store, access, and share files from smartphones and tablets without relying on local device storage. Examples include iCloud, Google Drive, and Dropbox accessed via mobile apps." },
  { term:"Multifactor Authentication (MFA)", def:"An authentication method requiring users to present two or more independent verification factors — something you know (password), something you have (token/phone), and/or something you are (biometric) — significantly reducing the risk of credential-based attacks." },
  { term:"Multitenancy", def:"A cloud architecture where multiple customers (tenants) share the same physical infrastructure and software instances while their data and operations remain logically isolated from each other. Enables cloud providers to achieve economies of scale." },
  { term:"Network-Based Intrusion Detection System (NIDS)", def:"An IDS that monitors network traffic at strategic points to detect malicious activity, policy violations, and suspicious patterns. Unlike HIDS, NIDS does not monitor individual hosts but captures and analyzes packets traversing the network segment." },
  { term:"NIST SP 800-123", def:"NIST Special Publication 800-123: Guide to General Server Security. Provides recommendations for securing server operating systems and applications, including patching, account management, services hardening, and logging. Applicable to cloud-hosted server workloads." },
  { term:"NIST SP 800-14", def:"NIST Special Publication 800-14: Generally Accepted Principles and Practices for Securing Information Technology Systems. Establishes foundational principles including accountability, awareness, ethics, multidisciplinary approach, and integration of security into the system lifecycle." },
  { term:"NIST SP 800-145", def:"NIST Special Publication 800-145: The NIST Definition of Cloud Computing. The authoritative definition establishing the five essential characteristics, three service models (IaaS/PaaS/SaaS), and four deployment models (public/private/community/hybrid) of cloud computing." },
  { term:"NIST SP 800-146", def:"NIST Special Publication 800-146: Cloud Computing Synopsis and Recommendations. A companion to SP 800-145 providing technical analysis of cloud computing, covering benefits, risks, security considerations, and recommendations for organizations adopting cloud services." },
  { term:"NIST SP 800-53r4", def:"NIST Special Publication 800-53 Revision 4: Security and Privacy Controls for Federal Information Systems and Organizations. Provides a catalog of security and privacy controls organized into 18 families, used as the baseline for FedRAMP and federal information system authorization." },
  { term:"Nonrepudiation", def:"The assurance that a party to a communication or transaction cannot later deny their participation or the authenticity of their actions. Achieved through digital signatures, audit logs, and timestamps. A key security service alongside confidentiality, integrity, and availability." },
  { term:"Object Storage", def:"A data storage architecture that manages data as objects — each containing the data itself, metadata, and a globally unique identifier — rather than as files in a hierarchy or blocks on a disk. Highly scalable and durable; used by AWS S3, Azure Blob Storage, and Google Cloud Storage." },
  { term:"Online Backup", def:"An automated service that copies and stores data backups to remote servers over the internet. Provides off-site protection, version history, and recovery capabilities without physical media management. Suitable for individuals and businesses as a disaster recovery component." },
  { term:"OpenID", def:"An open standard and decentralized authentication protocol that allows users to authenticate with a single set of credentials across multiple websites. OpenID Connect (OIDC) is the modern version built on OAuth 2.0, providing identity verification and basic profile information via JWT tokens." },
  { term:"Open Web Application Security Project (OWASP)", def:"A nonprofit foundation dedicated to improving software security. Produces freely available resources including the OWASP Top 10 (most critical web application risks), testing guides, and security development frameworks used globally by developers and security professionals." },
  { term:"Operational Level Agreement (OLA)", def:"An internal agreement between different teams or units within an organization (e.g., IT operations and a service desk) defining responsibilities and performance targets that together support a Service Level Agreement (SLA) delivered to the end customer." },
  { term:"Organizational Normative Framework (ONF)", def:"The complete set of policies, standards, regulations, and compliance requirements that apply to an organization's IT and cloud environment. The ONF drives which security controls must be implemented and serves as the reference for the Application Normative Framework (ANF)." },
  { term:"Oversubscription", def:"A practice in cloud and network environments of allocating more virtual resources than the underlying physical capacity can simultaneously support. Works on the assumption that not all customers will use their full allocation at the same time, enabling cost efficiency but potentially causing contention." },
  { term:"Payment Card Industry Security Standards Council (PCI SSC)", def:"The global body founded by American Express, Discover, JCB, Mastercard, and Visa that manages the Payment Card Industry Data Security Standard (PCI DSS). Sets security requirements for organizations that store, process, or transmit cardholder data." },
  { term:"Penetration Test", def:"An authorized simulated cyberattack performed by security professionals (ethical hackers) against a target system to identify exploitable vulnerabilities. Results are documented in a report with findings and remediation recommendations. Types include black-box, white-box, and gray-box testing." },
  { term:"Personal Cloud Storage", def:"Cloud storage solutions intended for individual consumer use, enabling personal files, photos, and documents to be stored and accessed from multiple devices. Examples include iCloud, Google Drive, OneDrive, and Dropbox. Distinct from enterprise cloud storage in scale and governance." },
  { term:"Personal Data", def:"Any information relating to an identified or identifiable natural person ('data subject'). Under GDPR, personal data includes names, identification numbers, location data, online identifiers, or factors specific to the physical, physiological, genetic, mental, economic, cultural, or social identity of a person." },
  { term:"Personal Health Information (PHI)", def:"Any individually identifiable health information held or transmitted by a covered entity or business associate in any form. Includes medical records, diagnoses, treatment information, payment information, and any other data that could identify an individual's health status. Protected under HIPAA." },
  { term:"Personally Identifiable Information (PII)", def:"Any data that can be used to identify a specific individual, alone or in combination with other information. Includes names, Social Security numbers, birthdates, addresses, biometric data, email addresses, and IP addresses. Subject to privacy laws such as GDPR, CCPA, and HIPAA." },
  { term:"Platform as a Service (PaaS)", def:"A cloud service model that provides customers with a platform — including runtime environment, development tools, databases, and middleware — on which to develop, run, and manage applications without managing the underlying infrastructure." },
  { term:"Portability", def:"In cloud computing, the ability to move applications, data, and workloads from one cloud environment to another (or back on-premises) without significant rework. Reduces vendor lock-in and enables organizations to optimize costs and capabilities across providers." },
  { term:"Privacy Level Agreement (PLA)", def:"A contractual agreement between a cloud service provider and customer that specifies privacy protection obligations, data handling practices, and compliance commitments. Extends traditional SLAs to address privacy-specific requirements such as data location, retention, and subject rights." },
  { term:"Private Cloud", def:"A cloud deployment model where the infrastructure is provisioned for exclusive use by a single organization. May be owned, managed, and operated by the organization, a third party, or a combination, and may be on or off premises. Offers greater control and security than public cloud." },
  { term:"Private Cloud Project", def:"An initiative to design, build, and deploy a cloud computing environment dedicated to a single organization. Involves selecting virtualization technology, designing network architecture, implementing security controls, and establishing self-service provisioning capabilities." },
  { term:"Private Cloud Security", def:"The set of security controls, policies, and practices applied to protect a private cloud environment. While the organization has greater control than in public cloud, it retains full responsibility for physical, network, hypervisor, operating system, and application security." },
  { term:"Private Cloud Storage", def:"Storage infrastructure deployed within a private cloud environment, accessible only to an organization's authorized users. Provides the scalability benefits of cloud storage combined with the data control and security of on-premises infrastructure." },
  { term:"Public Cloud", def:"A cloud deployment model where services are provided over the public internet and shared across multiple organizations (tenants). Infrastructure is owned and operated by the cloud provider. Offers high scalability and cost efficiency with a shared responsibility security model." },
  { term:"Public Cloud Storage", def:"Storage services offered by public cloud providers (AWS S3, Azure Blob, Google Cloud Storage) accessible over the internet. Organizations share the underlying infrastructure with other tenants while retaining logical isolation. Highly scalable, durable, and globally accessible." },
  { term:"Public Key Encryption", def:"An asymmetric encryption system in which a publicly shareable key is used to encrypt data, and only the corresponding private key (kept secret by the owner) can decrypt it. Underpins HTTPS, email encryption (PGP/S-MIME), and digital certificates." },
  { term:"Qualitative Assessment (QA)", def:"A risk assessment approach that uses descriptive scales (e.g., High/Medium/Low) rather than numerical values to evaluate likelihood and impact of risks. More subjective but faster and requires less data than quantitative assessment. Useful for initial risk screening." },
  { term:"Quality of Service (QoS)", def:"A set of technologies and mechanisms that manage network traffic to ensure performance requirements — bandwidth, latency, jitter, and packet loss — are met for critical applications. In cloud SLAs, QoS metrics define the performance standards the provider commits to deliver." },
  { term:"Quantitative Assessment", def:"A risk assessment methodology that assigns numerical values (monetary or statistical) to risk components — asset value, threat likelihood, and impact — to calculate expected losses. Produces measurable outputs like ALE, enabling cost-benefit analysis of security controls." },
  { term:"Random Access Memory (RAM)", def:"Volatile computer memory that stores data and machine code currently being used or processed by the CPU. In cloud computing, RAM is a key compute resource allocated to virtual machines and containers. Data in RAM is lost when power is removed." },
  { term:"Record", def:"In a legal and compliance context, any documented evidence of activities, transactions, or events that must be retained for business, legal, or regulatory purposes. Records management policies define retention periods, storage requirements, and secure disposal procedures." },
  { term:"Recovery Point Objective (RPO)", def:"The maximum acceptable amount of data loss measured in time — the point to which data must be restored after a disaster. Determines backup frequency requirements. An RPO of 4 hours means systems can be restored to a state no more than 4 hours before the failure." },
  { term:"Recovery Time Objective (RTO)", def:"The maximum acceptable duration of time a system or process can be offline after a disaster before the impact becomes unacceptable. Drives the design of disaster recovery solutions. Lower RTOs require more expensive, active-active or hot-standby architectures." },
  { term:"Reduced Sign-On (RSO)", def:"An authentication approach that reduces the number of times users must authenticate by sharing credentials or session tokens across a limited set of systems, without achieving full single sign-on. A practical intermediate step for organizations not yet fully implementing SSO." },
  { term:"Redundant Array of Inexpensive Disks (RAID)", def:"A data storage virtualization technology that combines multiple physical disk drives into one logical unit for redundancy, performance improvement, or both. Common levels include RAID 0 (striping), RAID 1 (mirroring), RAID 5 (striping with parity), and RAID 10 (mirroring+striping)." },
  { term:"Remote Desktop Protocol (RDP)", def:"A Microsoft protocol that enables users to remotely access and control a computer over a network. Widely used for remote administration of Windows servers. A frequent target for brute-force and exploitation attacks, particularly when exposed to the internet." },
  { term:"Representational State Transfer (REST)", def:"An architectural style for designing networked applications using standard HTTP methods (GET, POST, PUT, DELETE). RESTful APIs are stateless, scalable, and widely used for cloud service integration. Data is typically exchanged in JSON or XML format." },
  { term:"Request for Proposal (RFP)", def:"A formal document organizations issue to solicit bids from potential vendors for products or services. In cloud procurement, RFPs outline technical requirements, security standards, compliance obligations, SLA expectations, and evaluation criteria." },
  { term:"Return on Investment (ROI)", def:"A performance measure evaluating the efficiency of an investment. Calculated as (Net Profit / Cost of Investment) × 100. In cloud security, ROI analysis compares the cost of security controls against the expected reduction in losses from prevented incidents." },
  { term:"Reversibility", def:"In cloud computing, the ability to retrieve all stored data and migrate it out of a cloud environment in a usable format, then have it completely deleted by the provider. Addresses data portability and vendor lock-in concerns; increasingly required in cloud contracts and regulations." },
  { term:"Sandboxing", def:"An isolation technique that runs programs or code in a restricted, controlled environment separated from production systems. Used to analyze potentially malicious code, test untrusted applications, and prevent compromise of the host system. Common in malware analysis and secure browsing." },
  { term:"Sarbanes-Oxley Act (SOX)", def:"U.S. federal legislation enacted in 2002 establishing financial reporting and audit requirements for publicly traded companies. Section 404 requires management to assess internal controls over financial reporting; Section 302 requires executives to certify financial statements. Has significant IT audit implications." },
  { term:"Secret Sharing Made Short (SSMS)", def:"A cryptographic scheme that combines information dispersal and secret sharing to securely split sensitive data into multiple shares distributed across different locations. Data can only be reconstructed if a minimum threshold of shares is combined. Used in secure cloud storage architectures." },
  { term:"Security Assertion Markup Language (SAML)", def:"An XML-based open standard for exchanging authentication and authorization data between an identity provider (IdP) and a service provider (SP). Enables browser-based SSO in enterprise environments. SAML 2.0 is widely used for federated identity management." },
  { term:"Security Information and Event Management (SIEM)", def:"A solution that aggregates, correlates, and analyzes log data and security events from multiple sources across the IT environment. Provides real-time threat detection, alerts, incident investigation capabilities, and compliance reporting through centralized visibility." },
  { term:"Sensitive Data", def:"Information that must be protected from unauthorized access due to its confidential nature, legal requirements, or potential harm from disclosure. Categories include PII, PHI, financial data, trade secrets, and classified information. Requires higher levels of protection than general business data." },
  { term:"Service-Level Agreement (SLA)", def:"A contract between a service provider and customer that defines expected service levels including uptime guarantees, performance metrics, response times, and security obligations. SLAs should specify remedies (e.g., service credits) for failures to meet agreed standards." },
  { term:"Service Organization Controls 1 (SOC 1)", def:"An audit report focused on internal controls relevant to a service organization's financial reporting. Based on the SSAE 18 standard, SOC 1 reports (Type I and Type II) are used by auditors of user organizations to assess risks related to outsourced financial processes." },
  { term:"Service Organization Controls 2 (SOC 2)", def:"An audit report evaluating a service organization's controls related to the Trust Services Criteria: Security, Availability, Processing Integrity, Confidentiality, and Privacy. Type II reports cover a period of time (usually 6–12 months), providing evidence of operating effectiveness." },
  { term:"Simple Object Access Protocol (SOAP)", def:"A protocol for exchanging structured information in web services using XML. SOAP messages are highly structured with a defined envelope, header, and body. More rigid and verbose than REST but offers built-in standards for security (WS-Security), transactions, and reliability." },
  { term:"Single Loss Expectancy (SLE)", def:"The monetary value expected to be lost in a single occurrence of a specific risk event. Calculated as SLE = Asset Value × Exposure Factor (EF). A component of quantitative risk analysis; combined with ARO to calculate Annual Loss Expectancy (ALE)." },
  { term:"Single Sign-On (SSO)", def:"An authentication mechanism allowing a user to log in once and gain access to multiple related but independent systems without re-authenticating for each. Improves user experience and reduces password fatigue while centralizing access control and audit logging." },
  { term:"Software as a Service (SaaS)", def:"A cloud delivery model where software applications are hosted by the provider and delivered to customers over the internet via a browser or API, typically on a subscription basis. The provider manages all infrastructure, middleware, and application maintenance. Examples: Salesforce, Microsoft 365, Google Workspace." },
  { term:"Software Defined Networking (SDN)", def:"A network architecture approach that separates the control plane (decisions about where traffic goes) from the data plane (forwarding traffic), enabling centralized, programmable network management. Enhances agility, automation, and security policy enforcement in cloud environments." },
  { term:"Software Development Life Cycle (SDLC)", def:"A structured process for planning, creating, testing, deploying, and maintaining software. Security-focused SDLC integrates security requirements, threat modeling, code review, and penetration testing at each phase, commonly referred to as Secure SDLC or DevSecOps." },
  { term:"Solid-State Drive (SSD)", def:"A storage device that uses flash memory chips to store data persistently without moving parts. Significantly faster than traditional HDDs, more durable, and energy-efficient. Standard in modern servers and cloud infrastructure. Note: degaussing does not work on SSDs." },
  { term:"Static Application Security Testing (SAST)", def:"A white-box security testing method that analyzes application source code, bytecode, or binaries for security vulnerabilities without executing the program. Integrated into CI/CD pipelines to catch issues early in development. Complements DAST in a complete AppSec program." },
  { term:"Storage Cloud", def:"Cloud infrastructure dedicated to providing scalable data storage services over the internet. Storage clouds offer object, block, or file storage models with varying characteristics of performance, cost, and durability, used for backup, archiving, content distribution, and application data." },
  { term:"Storage Clusters", def:"Groups of storage nodes that work together as a unified storage system, providing increased capacity, performance, and redundancy. In cloud environments, storage clusters form the backbone of distributed storage systems, replicating data across nodes to ensure durability and availability." },
  { term:"STRIDE Threat Model", def:"A threat modeling framework developed by Microsoft that categorizes security threats into six types: Spoofing, Tampering, Repudiation, Information Disclosure, Denial of Service, and Elevation of Privilege. Used during system design to systematically identify and address potential vulnerabilities." },
  { term:"Threat Modeling", def:"A structured approach to identifying, analyzing, and mitigating potential security threats during the design phase of a system. Involves identifying assets, entry points, threat actors, and attack vectors, then applying countermeasures. Common frameworks include STRIDE, PASTA, and DREAD." },
  { term:"Tokenization", def:"A data protection technique that replaces sensitive data (e.g., credit card numbers) with non-sensitive substitute values called tokens. The original data is securely stored in a separate token vault. Tokens are meaningless if intercepted and reduce the scope of PCI DSS compliance." },
  { term:"Tort Law", def:"A branch of civil law addressing wrongful acts (torts) that cause harm to individuals or organizations, enabling victims to seek compensation. In cybersecurity, tort law applies to negligence claims arising from data breaches, privacy violations, and failure to implement reasonable security controls." },
  { term:"Traditional Network Model", def:"A conventional three-tier network architecture comprising core, distribution, and access layers using physical hardware (routers, switches, firewalls). Contrasts with software-defined networking (SDN) and cloud networking models in terms of agility, programmability, and management complexity." },
  { term:"Vendor Lock-In", def:"The dependence on a specific cloud provider or technology vendor that makes switching to an alternative prohibitively difficult, expensive, or risky due to proprietary formats, APIs, services, or contractual terms. Mitigated through portability standards, open APIs, and multi-cloud strategies." },
  { term:"Virtualization", def:"The creation of a virtual (rather than physical) version of a resource — such as a server, storage device, or network — using software abstraction. Enables multiple virtual resources to run on single physical hardware, improving utilization, flexibility, and management efficiency." },
  { term:"Virtualization Technologies", def:"Software platforms and tools that implement virtualization, including hypervisors (VMware ESXi, Microsoft Hyper-V, KVM), container runtimes (Docker, containerd), and virtual networking components. The foundational technology layer of cloud computing infrastructure." },
  { term:"Virtual Machine Introspection (VMI)", def:"A security technique that monitors the internal state of a virtual machine from the hypervisor layer, outside the guest OS. Provides tamper-resistant visibility into VM memory, processes, and network activity without relying on agents inside the VM, used in advanced malware detection." },
  { term:"Volume Storage", def:"Block-level cloud storage that functions like a virtual hard drive attached to a compute instance. Provides low-latency, high-performance storage for databases and applications requiring direct block access. Examples include AWS EBS (Elastic Block Store) and Azure Managed Disks." },
  { term:"Vulnerability Assessment", def:"A systematic process of identifying, quantifying, and prioritizing vulnerabilities in a system, network, or application. Unlike penetration testing, vulnerability assessments typically do not exploit findings but produce a prioritized list of weaknesses for remediation. Part of a continuous risk management program." },
  { term:"Web Application Firewall (WAF)", def:"A security solution that monitors, filters, and blocks HTTP/HTTPS traffic to and from a web application. Protects against common attacks including SQL injection, XSS, CSRF, and OWASP Top 10 vulnerabilities. Can be deployed as hardware, software, or cloud-based service." },
  { term:"XML Gateway", def:"A security appliance or service that validates, filters, and controls XML-based web service traffic. Protects against XML-specific attacks such as XML injection, XXE (XML External Entity), and SOAP-based threats while enforcing schema validation and access control policies for APIs and web services." },
  { term:"Zero-Day Vulnerability", def:"A software vulnerability unknown to the vendor or the public at the time of discovery, for which no patch or fix yet exists. Named because developers have had 'zero days' to address the flaw. Zero-day exploits are highly valuable to attackers and nation-state actors." },
  { term:"Zero Trust", def:"A security model based on the principle 'never trust, always verify' — no user, device, or network segment is inherently trusted regardless of location. Access is continuously validated using identity, device health, and context. Implemented through microsegmentation, MFA, and least-privilege access." },
  { term:"Prompt Injection", def:"An attack where crafted input manipulates a large language model into ignoring its instructions or producing unintended output. Untrusted external content (e.g., in RAG) must be treated as hostile, with output validation and guardrails." },
  { term:"Jailbreak (LLM)", def:"A technique that bypasses an AI model's safety guardrails to elicit restricted or harmful responses, often via role-play or obfuscated prompts." },
  { term:"Data Poisoning", def:"Corrupting an AI model's training data so the resulting model behaves incorrectly or contains a backdoor. A supply-chain risk for machine-learning pipelines." },
  { term:"Model Inversion", def:"An attack that reconstructs representative features of training data from a model's outputs, potentially exposing sensitive information." },
  { term:"Membership Inference", def:"An attack that determines whether a specific record was part of a model's training set — a privacy concern for models trained on personal data." },
  { term:"Model Extraction", def:"Stealing a proprietary model's parameters or behavior by systematically querying it and training a substitute (model theft)." },
  { term:"Retrieval-Augmented Generation (RAG)", def:"An architecture that supplies a large language model with external documents at query time to ground its answers. The retrieved content must be treated as untrusted input." },
  { term:"Large Language Model (LLM)", def:"A neural network trained on vast text corpora to understand and generate natural language, underpinning generative AI applications such as chatbots and copilots." },
  { term:"Generative AI", def:"AI systems that create new content (text, images, code) rather than only classifying or predicting. Introduces risks such as prompt injection, hallucination, and data leakage." },
  { term:"Hallucination (AI)", def:"When a generative model produces confident but false or fabricated output. A reliability and data-integrity risk requiring human oversight and validation." },
  { term:"Insecure Output Handling", def:"An LLM vulnerability where unvalidated model output is passed to downstream systems (browsers, interpreters, shells), enabling XSS, SSRF, or code injection." },
  { term:"AI Red-Teaming", def:"Adversarial testing of AI systems to uncover harmful, biased, or unsafe behaviors before deployment." },
  { term:"Guardrails (AI)", def:"Controls that constrain an AI system's inputs and outputs — input filtering, output validation, allow/deny lists — to enforce safe, policy-compliant behavior." },
  { term:"Shadow AI", def:"Unsanctioned use of AI tools or services by employees without organizational approval or governance, creating data-leakage and compliance risks." },
  { term:"NIST AI Risk Management Framework (AI RMF)", def:"A voluntary NIST framework to Govern, Map, Measure, and Manage AI risks. It is guidance, not a certification, and does not replace privacy laws." },
  { term:"ISO/IEC 42001", def:"An international standard specifying requirements for an Artificial Intelligence Management System (AIMS) — a certifiable framework for governing AI responsibly." },
  { term:"EU AI Act", def:"European Union regulation that classifies AI systems by risk. High-risk systems face conformity assessments, risk management, and transparency obligations; some uses are prohibited outright." },
  { term:"AI TRiSM", def:"AI Trust, Risk and Security Management — a discipline and set of controls ensuring AI model governance, trustworthiness, fairness, robustness, and data protection." },
  { term:"Confidential Computing", def:"Protecting data in use by processing it inside a hardware-based Trusted Execution Environment (TEE), complementing encryption at rest and in transit." },
  { term:"Trusted Execution Environment (TEE)", def:"A secure, isolated area of a processor that guarantees the confidentiality and integrity of code and data loaded inside it; the basis for confidential computing." },
  { term:"Post-Quantum Cryptography (PQC)", def:"Cryptographic algorithms designed to resist attacks by quantum computers, addressing harvest-now-decrypt-later threats to today's encrypted data." },
  { term:"Harvest-Now-Decrypt-Later", def:"An attack strategy where adversaries capture encrypted data today to decrypt it later once quantum computers can break current algorithms." },
  { term:"Software Bill of Materials (SBOM)", def:"A formal, machine-readable inventory of all components and dependencies in a software product, used for vulnerability management and supply-chain security." },
  { term:"Zero Trust Architecture (ZTA)", def:"A security model that assumes no implicit trust and continuously verifies every access request based on identity, device posture, and context, regardless of network location." },
  { term:"Explainable AI (XAI)", def:"Techniques that make AI model decisions interpretable to humans, supporting transparency, auditability, and regulatory compliance." },
  { term:"Foundation Model", def:"A large model trained on broad data that can be adapted (fine-tuned) to many downstream tasks; its provenance and integrity are supply-chain concerns." }
];
GLOSSARY_CCSP.sort((a, b) => a.term.localeCompare(b.term, undefined, { sensitivity: 'base' }));
